386		}
387	
388		artifactRef := fmt.Sprintf("%s/%s@%s", suiteChartProject, name, digest)
389		schemaBytes, err := orasClient.PullFile(ctx, artifactRef, jsonSchemaFileName, maxSchemaSize)
390		if err != nil {
391			log.Errorf("failed to pull custom value schema from artifact %s: %v", artifactRef, err)
392			return nil, fmt.Errorf("failed to pull custom value schema from artifact %s: %w", artifactRef, err)
393		}
394		if json.Valid(schemaBytes) {
395			return json.RawMessage(schemaBytes), nil
396		} else {
397			log.Errorf("custom value schema pulled from artifact %s is not valid JSON", artifactRef)
398			return nil, fmt.Errorf("custom value schema pulled from artifact %s is not valid JSON", artifactRef)
399		}
400	}
