562	// 入参底层数组可能会被修改
563	func disruptiveMergeAiSuites(suitesInRegistry []*aisuite.ProfileAISuite, suitesInCluster []*aisuite.ProfileAISuite) []*aisuite.ProfileAISuite {
564		smaller := suitesInRegistry
565		larger := suitesInCluster
566		clusterLarger := true
567		if len(suitesInCluster) < len(suitesInRegistry) {
568			smaller = suitesInCluster
569			larger = suitesInRegistry
570			clusterLarger = false
571		}
572	
573		result := smaller
574		suiteMap := make(map[string]int, len(smaller))
575		for idx, suite := range smaller {
576			suiteMap[suite.Name] = idx
577		}
578		for _, suite := range larger {
579			idx, exist := suiteMap[suite.Name]
580			if exist && clusterLarger {
581				result[idx] = suite
582			}
583			if !exist {
584				result = append(result, suite)
585			}
586		}
587		return result
588	}
589	
590	// expandDotKey inserts a value into a nested map by expanding dot-separated keys.
591	// E.g. expandDotKey(m, "global.image.tag", "v1.0.0") sets m["global"]["image"]["tag"] = "v1.0.0".
592	// This matches the behavior of `helm install --set global.image.tag=v1.0.0`.
593	func expandDotKey(m map[string]interface{}, key string, value interface{}) {
594		dotIdx := strings.Index(key, ".")
595		if dotIdx == -1 {
596			m[key] = value
597			return
598		}
599		prefix := key[:dotIdx]
600		rest := key[dotIdx+1:]
601		sub, ok := m[prefix].(map[string]interface{})
602		if !ok {
603			sub = make(map[string]interface{})
604			m[prefix] = sub
605		}
606		expandDotKey(sub, rest, value)
607	}
