609	func getSuiteRegistry(dbInstance *gorm.DB) (*db.Repository, error) {
610		registryModel := &db.Repository{}
611		suiteRegistry, err := registryModel.GetOrderBy(dbInstance, "created_at", false)
612		if err != nil {
613			log.Errorf("get suite registry failed: %v", err)
614			return nil, err
615		}
616	
617		// 数据合法性检查：防止数据库脏数据或空结果
618		if suiteRegistry.Id == 0 {
619			log.Error("suite registry not found or invalid: Id is zero")
620			return nil, fmt.Errorf("suite registry not found")
621		}
622		if suiteRegistry.Name == "" {
623			log.Error("suite registry has invalid data: Name is empty")
624			return nil, fmt.Errorf("suite registry data is incomplete")
625		}
626		if suiteRegistry.Address == "" {
627			log.Errorf("suite registry[%s] has invalid data: Address is empty", suiteRegistry.Name)
628			return nil, fmt.Errorf("suite registry data is incomplete")
629		}
630		return suiteRegistry, nil
631	}
