func (c *Controller) OperateAISuiteInCluster(ctx *gin.Context, req *aisuite.OperateAISuiteReq) (*aisuite.GetAISuiteResp, error) {
	effectiveNamespace := req.Namespace
	switch req.Action {
	case ActionUninstall:
		if err := c.uninstallAISuiteInCluster(req.ClusterCode, req.Name, req.Namespace); err != nil {
			return nil, fmt.Errorf("failed to uninstall AI Suite %s in cluster %s: %w", req.Name, req.ClusterCode, err)
		}
		c.setPendingStatus(req.ClusterCode, req.Name, effectiveNamespace, optimisticPendingUninstall, "")
	case ActionInstall:
		// 执行安装操作
		effectiveNamespace = getNamespaceFromCustomValues(req.CustomValues)
		if err := c.installAISuiteInCluster(req.ClusterCode, req.Name, req.ChartVersion, req.CustomValues); err != nil {
			return nil, fmt.Errorf("failed to install AI Suite %s in cluster %s: %w", req.Name, req.ClusterCode, err)
		}
		c.setPendingStatus(req.ClusterCode, req.Name, effectiveNamespace, optimisticPendingInstall, req.ChartVersion)
	case ActionUpgrade:
		// 执行升级操作
		if err := c.upgradeAISuiteInCluster(req.ClusterCode, req.Namespace, req.Name, req.ChartVersion, req.CustomValues); err != nil {
			return nil, fmt.Errorf("failed to upgrade AI Suite %s in cluster %s: %w", req.Name, req.ClusterCode, err)
		}
		c.setPendingStatus(req.ClusterCode, req.Name, effectiveNamespace, optimisticPendingUpgrade, req.ChartVersion)
	default:
		return nil, fmt.Errorf("unsupported operation: %s", req.Action)
	}

	return buildOptimisticSuiteResp(req), nil
}

func optimisticStatus(action string) string {
	switch action {
	case ActionInstall:
		return optimisticPendingInstall
	case ActionUpgrade:
		return optimisticPendingUpgrade
	case ActionUninstall:
		return optimisticPendingUninstall
	default:
		return ""
	}
}

func buildOptimisticSuiteResp(req *aisuite.OperateAISuiteReq) *aisuite.GetAISuiteResp {
	resp := &aisuite.GetAISuiteResp{
		ProfileAISuite: &aisuite.ProfileAISuite{
			Name:      req.Name,
			Status:    optimisticStatus(req.Action),
			Namespace: req.Namespace,
		},
		InCluster:   req.Action != ActionInstall,
		VersionList: make([]*aisuite.AISuiteVersion, 0, 1),
	}

	if req.Action != ActionUninstall {
		resp.ProfileAISuite.Version = &aisuite.AISuiteVersion{
			ChartVersion:   req.ChartVersion,
			DisplayVersion: req.ChartVersion,
		}
		resp.VersionList = append(resp.VersionList, resp.ProfileAISuite.Version)
	}

	return resp
}

