	}
	applyPendingToProfileSuite(suite.ProfileAISuite, pending)
}

// isClusterStateSettled 检查集群的实际状态是否已经反映了 pending 操作的预期结果。
// 如果已经到位，返回 true，调用方应清除 pending 而不是继续覆盖。
func (c *Controller) isClusterStateSettled(suite *aisuite.ProfileAISuite, pending *pendingSuiteState) bool {
	if suite == nil || pending == nil {
		return false
	}
	switch pending.Status {
	case optimisticPendingInstall:
		// 集群状态已经变为 deployed，说明安装完成
		return suite.Status == "deployed"
	case optimisticPendingUpgrade:
		// 集群已 deployed 且版本已更新到目标版本，说明升级完成
		if suite.Status != "deployed" {
			return false
		}
		if pending.ChartVersion == "" {
			return true
		}
		return suite.Version != nil && suite.Version.ChartVersion == pending.ChartVersion
	case optimisticPendingUninstall:
		// 如果套件状态已经变为 undeployed（来自 registry 合并结果），说明卸载完成
		return suite.Status == deployStatusUndeployed
	}
	return false
}

func applyPendingToProfileSuite(suite *aisuite.ProfileAISuite, pending *pendingSuiteState) {
	if suite == nil || pending == nil {
		return
	}
	suite.Status = pending.Status
	if pending.Namespace != "" {
		suite.Namespace = pending.Namespace
	}
	if suite.Version != nil && pending.ChartVersion != "" {
		suite.Version.ChartVersion = pending.ChartVersion
		if suite.Version.AppVersion != "" {
			suite.Version.DisplayVersion = getDisplayVersion(suite.Version.AppVersion, pending.ChartVersion)
		} else {
			suite.Version.DisplayVersion = pending.ChartVersion
		}
	}
}

