	client, err := ac.GetApiserverClient(clusterCode)
	if err != nil {
		return nil, err
	}
	path := "/tap/api/v1/helm/releases/" + namespace + "/" + name
	querys := &url.Values{}

	res := &helm.ReleaseElement{}
	err = client.Do("GET", path, querys, nil, res)
	if err != nil {
		return nil, err
	}
	return res, nil
}

func (ac *ApiserverCache) GetHelmReleaseValues(clusterCode string, namespace, name string, revision int, allValues bool) (map[string]interface{}, error) {
