23	)
24	
25	type Controller struct {
26		db              *gorm.DB
27		apiserverGetter manager.ApiserverGetter
28	}
29	
30	const (
31		suiteProjectPrefix  = "zzzz_internal_ai_suite"
32		suiteChartProject   = suiteProjectPrefix + "_helm_charts"
33		chartArtifactType   = "CHART"
34		jsonSchemaFileName  = "tap_aisuite_values.json"
35		readmeFileName      = "README.md"
36		aisuiteReleaseLabel = "DeployedBy=TAPAISuite"
37		maxSchemaSize       = 1024 * 1024 // 单位：字节
38		wait                = true
39		waitTimeout         = 10 * time.Minute
40		helmParamPrefix     = "tap_aisuite_"
41	)
42	
43	const (
44		deployStatusUndeployed = "undeployed"
45	)
46	
47	const (
48		ActionInstall   = "install"
49		ActionUpgrade   = "upgrade"
50		ActionUninstall = "uninstall"
51	)
52	
53	const (
54		optimisticPendingInstall   = "pending-install"
55		optimisticPendingUpgrade   = "pending-upgrade"
56		optimisticPendingUninstall = "pending-uninstall"
57	)
58	
59	func NewController(db *gorm.DB, apiserverGetter manager.ApiserverGetter) (*Controller, error) {
60		return &Controller{
61			db:              db,
62			apiserverGetter: apiserverGetter,
63		}, nil
64	}
65	
66	func (c *Controller) ListAISuites(ctx *gin.Context, clusterCode string) (*aisuite.ListAISuitesResp, error) {
67		suiteRegistry, err := getSuiteRegistry(c.db)
68		var aiSuitesInRegistry []*aisuite.ProfileAISuite
69		if err != nil {
70			log.Errorf("failed to get suite registry: %v", err)
71		} else {
72			aiSuitesInRegistry, err = listAISuitesInRegistry(ctx, suiteRegistry)
73			if err != nil {
74				log.Errorf("failed to list AI Suites in registry: %v", err)
75			}
76		}
77	
78		aiSuitesInCluster, err := c.listAISuitesInCluster(clusterCode)
79		// 如果查询集群内套件失败，应该直接返回报错，防止用户下一步操作部署一个已经在集群里部署了的套件（因为用户看不到集群里的套件列表，以为没有，所以又部署了一个）
80		if err != nil {
81			log.Errorf("failed to list AI Suites in cluster: %v", err)
82			return nil, fmt.Errorf("failed to list AI Suites in cluster: %w", err)
83		}
84	
85		// 入参底层数组可能会被修改，如果后面要增加逻辑，注意处理
86		aiSuites := disruptiveMergeAiSuites(aiSuitesInRegistry, aiSuitesInCluster)
87		sort.Slice(aiSuites, func(i, j int) bool {
88			return aiSuites[i].Name < aiSuites[j].Name
89		})
90		return &aisuite.ListAISuitesResp{
91			Total: len(aiSuites),
92			Data:  aiSuites,
93		}, nil
94	}
95	
96	func (c *Controller) GetAISuite(ctx *gin.Context, clusterCode, name, chartVersion, namespace string) (*aisuite.GetAISuiteResp, error) {
97		// 从集群和registry中查询套件
98		suiteInCluster, err := c.getAISuiteInCluster(clusterCode, name, chartVersion, namespace)
99		if err != nil {
100			log.Errorf("encountered error while getting AI Suite in cluster: %v", err)
101			if namespace != "" {
102				return nil, fmt.Errorf("encountered error while getting AI Suite in cluster: %w", err)
103			}
104		}
105	
106		suiteInRegistry := new(aisuite.GetAISuiteResp)
107		suiteRegistry, err := getSuiteRegistry(c.db)
108		if err != nil {
109			log.Errorf("failed to get suite registry: %v", err)
110		} else {
111			suiteInRegistry, err = getAISuiteInRegistry(ctx, suiteRegistry, name, chartVersion)
112			if err != nil {
113				log.Errorf("encountered error while getting AI Suite in registry: %v", err)
114				suiteInRegistry = nil
115			}
116		}
117	
118		switch {
119		case suiteInCluster == nil && suiteInRegistry == nil:
120			return nil, fmt.Errorf("AI Suite %s not found in both cluster and registry", name)
121		case suiteInCluster != nil && suiteInRegistry == nil:
122			return suiteInCluster, nil
123		case suiteInCluster == nil && suiteInRegistry != nil:
124			return suiteInRegistry, nil
125		case suiteInCluster != nil && suiteInRegistry != nil:
126			if suiteInCluster.ProfileAISuite != nil && suiteInCluster.ProfileAISuite.Version != nil {
127				inBoth := false
128				for _, version := range suiteInRegistry.VersionList {
129					if version.DisplayVersion == suiteInCluster.ProfileAISuite.Version.DisplayVersion {
130						suiteInCluster.VersionList = suiteInRegistry.VersionList
131						inBoth = true
132						break
133					}
134				}
135				if !inBoth {
136					suiteInCluster.VersionList = append(suiteInCluster.VersionList, suiteInCluster.ProfileAISuite.Version)
137				}
138				// TODO: 用已部署套件的values的值覆盖schame中的默认值，提供给前端展示
139				// setValues, err := c.apiserverGetter.GetHelmReleaseValues(clusterCode, namespace, name, suiteInCluster.ProfileAISuite.Version.Revision, true)
140				// if err != nil {
141				// 	log.Errorf("failed to get helm release values: %v", err)
142				// }
143				// setValues中是嵌套map[string]interface{}的结构，需要转换成json字符串再赋值给CustomValueSchema中的
144			}
145			suiteInCluster.CustomValueSchema = suiteInRegistry.CustomValueSchema
146			return suiteInCluster, nil
147		}
148		return nil, nil
149	}
150	
151	func (c *Controller) GetAISuiteReadme(ctx context.Context, name, chartVersion string) (*aisuite.GetAISuiteReadmeResp, error) {
152		// 使用oras拉取chart，解压后读取其中的README.md, 作为套件的README内容
153		suiteRegistry, err := getSuiteRegistry(c.db)
154		if err != nil {
