172	func (c *Controller) OperateAISuiteInCluster(ctx *gin.Context, req *aisuite.OperateAISuiteReq) (*aisuite.GetAISuiteResp, error) {
173		switch req.Action {
174		case ActionUninstall:
175			if err := c.uninstallAISuiteInCluster(req.ClusterCode, req.Name, req.Namespace); err != nil {
176				return nil, fmt.Errorf("failed to uninstall AI Suite %s in cluster %s: %w", req.Name, req.ClusterCode, err)
177			}
178		case ActionInstall:
179			// 执行安装操作
180			if err := c.installAISuiteInCluster(req.ClusterCode, req.Name, req.ChartVersion, req.CustomValues); err != nil {
181				return nil, fmt.Errorf("failed to install AI Suite %s in cluster %s: %w", req.Name, req.ClusterCode, err)
182			}
183		case ActionUpgrade:
184			// 执行升级操作
185			if err := c.upgradeAISuiteInCluster(req.ClusterCode, req.Namespace, req.Name, req.ChartVersion, req.CustomValues); err != nil {
186				return nil, fmt.Errorf("failed to upgrade AI Suite %s in cluster %s: %w", req.Name, req.ClusterCode, err)
187			}
188		default:
189			return nil, fmt.Errorf("unsupported operation: %s", req.Action)
190		}
191	
192		return buildOptimisticSuiteResp(req), nil
193	}
