234	func (c *Controller) installAISuiteInCluster(clusterCode, name, chartVersion string, customValues []*aisuite.CustomValues) error {
235		suiteRegistry, err := getSuiteRegistry(c.db)
236		if err != nil {
237			log.Errorf("failed to get suite registry: %v", err)
238			return fmt.Errorf("failed to get suite registry: %w", err)
239		}
240		registryHost := strings.TrimPrefix(suiteRegistry.Address, "https://")
241		registryHost = strings.TrimPrefix(registryHost, "http://")
242		repoChart := fmt.Sprintf("oci://%s/%s/%s", registryHost, suiteChartProject, name)
243		setValues := make(map[string]interface{})
244		req := &helm.InstallOrUpgradeReleaseRequest{
245			HelmRepository: helm.HelmRepository{
246				Host:     registryHost,
247				UserName: suiteRegistry.User,
248				Password: suiteRegistry.Password,
249			},
250			CreateNamespace: true,
251			Name:            name,
252			Wait:            wait,
253			Timeout:         waitTimeout,
254			RepoChart:       repoChart,
255			Version:         chartVersion,
256			Labels:          map[string]string{"DeployedBy": "TAPAISuite"},
257		}
258		for _, cv := range customValues {
259			switch cv.Name {
260			case helmParamPrefix + "namespace":
261				namespace, ok := cv.Value.(string)
262				if !ok {
263					return fmt.Errorf("invalid type for namespace value: expected string, got %T", cv.Value)
264				}
265				req.Namespace = namespace
266			case helmParamPrefix + "timeout":
267				waitTimeoutFloat, ok := cv.Value.(float64) // JSON numbers are unmarshaled into float64
268				if !ok {
269					return fmt.Errorf("invalid type for timeout value: expected int, got %T", cv.Value)
270				}
271				waitTimeout := util.ToInt(waitTimeoutFloat)
272				req.Timeout = time.Duration(waitTimeout) * time.Second
273			default:
274				expandDotKey(setValues, cv.Name, cv.Value)
275			}
276		}
277		if req.Namespace == "" {
278			return fmt.Errorf("namespace is required for installing AI Suite in cluster")
279		}
280	
281		req.Values = setValues
282		return c.apiserverGetter.InstallRelease(clusterCode, req)
283	}
