293		registryHost = strings.TrimPrefix(registryHost, "http://")
294		repoChart := fmt.Sprintf("oci://%s/%s/%s", registryHost, suiteChartProject, name)
295		setValues := make(map[string]interface{})
296		req := &helm.InstallOrUpgradeReleaseRequest{
297			Wait:    wait,
298			Timeout: waitTimeout,
299		}
300		for _, cv := range customValues {
301			switch cv.Name {
302			case helmParamPrefix + "timeout":
303				waitTimeoutFloat, ok := cv.Value.(float64) // JSON numbers are unmarshaled into float64
304				if !ok {
305					return fmt.Errorf("invalid type for timeout value: expected int, got %T", cv.Value)
306				}
307				waitTimeout := util.ToInt(waitTimeoutFloat)
308				req.Timeout = time.Duration(waitTimeout) * time.Second
