601	// 入参底层数组可能会被修改
602	func disruptiveMergeAiSuites(suitesInRegistry []*aisuite.ProfileAISuite, suitesInCluster []*aisuite.ProfileAISuite) []*aisuite.ProfileAISuite {
603		clusterMap := make(map[string]*aisuite.ProfileAISuite, len(suitesInCluster))
604		for _, suite := range suitesInCluster {
605			clusterMap[suite.Name] = suite
606		}
607	
608		result := make([]*aisuite.ProfileAISuite, 0, len(suitesInRegistry)+len(suitesInCluster))
609		seen := make(map[string]bool, len(suitesInRegistry))
610		for _, suite := range suitesInRegistry {
611			if suiteInCluster, ok := clusterMap[suite.Name]; ok {
612				result = append(result, suiteInCluster)
613			} else {
614				result = append(result, suite)
615			}
616			seen[suite.Name] = true
617		}
618		for _, suite := range suitesInCluster {
619			if !seen[suite.Name] {
620				result = append(result, suite)
621			}
622		}
623		return result
624	}
