626	// expandDotKey inserts a value into a nested map by expanding dot-separated keys.
627	// E.g. expandDotKey(m, "global.image.tag", "v1.0.0") sets m["global"]["image"]["tag"] = "v1.0.0".
628	// This matches the behavior of `helm install --set global.image.tag=v1.0.0`.
629	func expandDotKey(m map[string]interface{}, key string, value interface{}) {
630		dotIdx := strings.Index(key, ".")
631		if dotIdx == -1 {
632			m[key] = value
633			return
634		}
635		prefix := key[:dotIdx]
636		rest := key[dotIdx+1:]
637		sub, ok := m[prefix].(map[string]interface{})
638		if !ok {
639			sub = make(map[string]interface{})
640			m[prefix] = sub
641		}
642		expandDotKey(sub, rest, value)
643	}
