645	func getSuiteRegistry(dbInstance *gorm.DB) (*db.Repository, error) {
646		registryModel := &db.Repository{}
647		suiteRegistry, err := registryModel.GetOrderBy(dbInstance, "created_at", false)
648		if err != nil {
649			log.Errorf("get suite registry failed: %v", err)
650			return nil, err
651		}
652	
653		// 数据合法性检查：防止数据库脏数据或空结果
654		if suiteRegistry.Id == 0 {
655			log.Error("suite registry not found or invalid: Id is zero")
656			return nil, fmt.Errorf("suite registry not found")
657		}
658		if suiteRegistry.Name == "" {
659			log.Error("suite registry has invalid data: Name is empty")
660			return nil, fmt.Errorf("suite registry data is incomplete")
661		}
662		if suiteRegistry.Address == "" {
663			log.Errorf("suite registry[%s] has invalid data: Address is empty", suiteRegistry.Name)
664			return nil, fmt.Errorf("suite registry data is incomplete")
665		}
666		return suiteRegistry, nil
667	}
