type Controller struct {
	db              *gorm.DB
	apiserverGetter manager.ApiserverGetter
}

const (
	suiteProjectPrefix  = "zzzz_internal_ai_suite"
	suiteChartProject   = suiteProjectPrefix + "_helm_charts"
	chartArtifactType   = "CHART"
	jsonSchemaFileName  = "tap_aisuite_values.json"
	readmeFileName      = "README.md"
	aisuiteReleaseLabel = "DeployedBy=TAPAISuite"
	maxSchemaSize       = 1024 * 1024 // 单位：字节
	wait                = true
	waitTimeout         = 10 * time.Minute
	helmParamPrefix     = "tap_aisuite_"
)

const (
	deployStatusUndeployed = "undeployed"
)

const (
	ActionInstall   = "install"
	ActionUpgrade   = "upgrade"
	ActionUninstall = "uninstall"
)

const (
	optimisticPendingInstall   = "pending-install"
	optimisticPendingUpgrade   = "pending-upgrade"
	optimisticPendingUninstall = "pending-uninstall"
)

func NewController(db *gorm.DB, apiserverGetter manager.ApiserverGetter) (*Controller, error) {
	return &Controller{
		db:              db,
		apiserverGetter: apiserverGetter,
	}, nil
}

func (c *Controller) ListAISuites(ctx *gin.Context, clusterCode string) (*aisuite.ListAISuitesResp, error) {
	suiteRegistry, err := getSuiteRegistry(c.db)
	var aiSuitesInRegistry []*aisuite.ProfileAISuite
	if err != nil {
		log.Errorf("failed to get suite registry: %v", err)
	} else {
		aiSuitesInRegistry, err = listAISuitesInRegistry(ctx, suiteRegistry)
		if err != nil {
			log.Errorf("failed to list AI Suites in registry: %v", err)
		}
	}

	aiSuitesInCluster, err := c.listAISuitesInCluster(clusterCode)
	// 如果查询集群内套件失败，应该直接返回报错，防止用户下一步操作部署一个已经在集群里部署了的套件（因为用户看不到集群里的套件列表，以为没有，所以又部署了一个）
	if err != nil {
		log.Errorf("failed to list AI Suites in cluster: %v", err)
		return nil, fmt.Errorf("failed to list AI Suites in cluster: %w", err)
	}

	// 入参底层数组可能会被修改，如果后面要增加逻辑，注意处理
	aiSuites := disruptiveMergeAiSuites(aiSuitesInRegistry, aiSuitesInCluster)
	sort.Slice(aiSuites, func(i, j int) bool {
		return aiSuites[i].Name < aiSuites[j].Name
	})
	return &aisuite.ListAISuitesResp{
		Total: len(aiSuites),
		Data:  aiSuites,
	}, nil
}

func (c *Controller) GetAISuite(ctx *gin.Context, clusterCode, name, chartVersion, namespace string) (*aisuite.GetAISuiteResp, error) {
	// 从集群和registry中查询套件
	suiteInCluster, err := c.getAISuiteInCluster(clusterCode, name, chartVersion, namespace)
	if err != nil {
		log.Errorf("encountered error while getting AI Suite in cluster: %v", err)
		if namespace != "" {
			return nil, fmt.Errorf("encountered error while getting AI Suite in cluster: %w", err)
		}
	}

	suiteInRegistry := new(aisuite.GetAISuiteResp)
	suiteRegistry, err := getSuiteRegistry(c.db)
	if err != nil {
		log.Errorf("failed to get suite registry: %v", err)
	} else {
		suiteInRegistry, err = getAISuiteInRegistry(ctx, suiteRegistry, name, chartVersion)
		if err != nil {
			log.Errorf("encountered error while getting AI Suite in registry: %v", err)
			suiteInRegistry = nil
		}
	}

	switch {
	case suiteInCluster == nil && suiteInRegistry == nil:
		return nil, fmt.Errorf("AI Suite %s not found in both cluster and registry", name)
	case suiteInCluster != nil && suiteInRegistry == nil:
		return suiteInCluster, nil
	case suiteInCluster == nil && suiteInRegistry != nil:
		return suiteInRegistry, nil
	case suiteInCluster != nil && suiteInRegistry != nil:
		if suiteInCluster.ProfileAISuite != nil && suiteInCluster.ProfileAISuite.Version != nil {
			inBoth := false
			for _, version := range suiteInRegistry.VersionList {
				if version.DisplayVersion == suiteInCluster.ProfileAISuite.Version.DisplayVersion {
					suiteInCluster.VersionList = suiteInRegistry.VersionList
					inBoth = true
					break
				}
			}
			if !inBoth {
				suiteInCluster.VersionList = append(suiteInCluster.VersionList, suiteInCluster.ProfileAISuite.Version)
			}
			// TODO: 用已部署套件的values的值覆盖schame中的默认值，提供给前端展示
			// setValues, err := c.apiserverGetter.GetHelmReleaseValues(clusterCode, namespace, name, suiteInCluster.ProfileAISuite.Version.Revision, true)
			// if err != nil {
			// 	log.Errorf("failed to get helm release values: %v", err)
			// }
			// setValues中是嵌套map[string]interface{}的结构，需要转换成json字符串再赋值给CustomValueSchema中的
		}
		suiteInCluster.CustomValueSchema = suiteInRegistry.CustomValueSchema
		return suiteInCluster, nil
	}
	return nil, nil
}

func (c *Controller) GetAISuiteReadme(ctx context.Context, name, chartVersion string) (*aisuite.GetAISuiteReadmeResp, error) {
	// 使用oras拉取chart，解压后读取其中的README.md, 作为套件的README内容
	suiteRegistry, err := getSuiteRegistry(c.db)
	if err != nil {
		log.Errorf("failed to get suite registry: %v", err)
		return nil, fmt.Errorf("failed to get suite registry: %w", err)
	}
	orasClient, err := oras.NewClient(suiteRegistry, oras.Insecure())
	if err != nil {
		log.Errorf("failed to create oras client: %v", err)
		return nil, fmt.Errorf("failed to create oras client: %w", err)
	}
	artifactRef := fmt.Sprintf("%s/%s:%s", suiteChartProject, name, chartVersion)
	readmeBytes, err := orasClient.PullFile(ctx, artifactRef, readmeFileName, maxSchemaSize)
	if err != nil {
		log.Errorf("failed to pull README.md for AI Suite %s:%s: %v", name, chartVersion, err)
		return nil, fmt.Errorf("failed to pull README.md for AI Suite %s:%s: %w", name, chartVersion, err)
	}
	return &aisuite.GetAISuiteReadmeResp{Readme: string(readmeBytes)}, nil
}

func (c *Controller) OperateAISuiteInCluster(ctx *gin.Context, req *aisuite.OperateAISuiteReq) (*aisuite.GetAISuiteResp, error) {
	switch req.Action {
	case ActionUninstall:
		if err := c.uninstallAISuiteInCluster(req.ClusterCode, req.Name, req.Namespace); err != nil {
			return nil, fmt.Errorf("failed to uninstall AI Suite %s in cluster %s: %w", req.Name, req.ClusterCode, err)
		}
	case ActionInstall:
		// 执行安装操作
		if err := c.installAISuiteInCluster(req.ClusterCode, req.Name, req.ChartVersion, req.CustomValues); err != nil {
			return nil, fmt.Errorf("failed to install AI Suite %s in cluster %s: %w", req.Name, req.ClusterCode, err)
		}
	case ActionUpgrade:
		// 执行升级操作
		if err := c.upgradeAISuiteInCluster(req.ClusterCode, req.Namespace, req.Name, req.ChartVersion, req.CustomValues); err != nil {
			return nil, fmt.Errorf("failed to upgrade AI Suite %s in cluster %s: %w", req.Name, req.ClusterCode, err)
		}
	default:
		return nil, fmt.Errorf("unsupported operation: %s", req.Action)
	}

	return buildOptimisticSuiteResp(req), nil
}

func optimisticStatus(action string) string {
	switch action {
	case ActionInstall:
		return optimisticPendingInstall
	case ActionUpgrade:
		return optimisticPendingUpgrade
	case ActionUninstall:
		return optimisticPendingUninstall
	default:
		return ""
	}
}

func buildOptimisticSuiteResp(req *aisuite.OperateAISuiteReq) *aisuite.GetAISuiteResp {
	resp := &aisuite.GetAISuiteResp{
		ProfileAISuite: &aisuite.ProfileAISuite{
			Name:      req.Name,
			Status:    optimisticStatus(req.Action),
			Namespace: req.Namespace,
		},
		InCluster:   req.Action != ActionInstall,
		VersionList: make([]*aisuite.AISuiteVersion, 0, 1),
	}

	if req.Action != ActionUninstall {
		resp.ProfileAISuite.Version = &aisuite.AISuiteVersion{
			ChartVersion:   req.ChartVersion,
			DisplayVersion: req.ChartVersion,
		}
		resp.VersionList = append(resp.VersionList, resp.ProfileAISuite.Version)
	}

	return resp
}

func (c *Controller) uninstallAISuiteInCluster(clusterCode, name, namespace string) error {
	return c.apiserverGetter.UninstallRelease(clusterCode, namespace, name)
}

func (c *Controller) installAISuiteInCluster(clusterCode, name, chartVersion string, customValues []*aisuite.CustomValues) error {
	suiteRegistry, err := getSuiteRegistry(c.db)
	if err != nil {
		log.Errorf("failed to get suite registry: %v", err)
		return fmt.Errorf("failed to get suite registry: %w", err)
	}
	registryHost := strings.TrimPrefix(suiteRegistry.Address, "https://")
	registryHost = strings.TrimPrefix(registryHost, "http://")
	repoChart := fmt.Sprintf("oci://%s/%s/%s", registryHost, suiteChartProject, name)
	setValues := make(map[string]interface{})
	req := &helm.InstallOrUpgradeReleaseRequest{
		HelmRepository: helm.HelmRepository{
			Host:     registryHost,
			UserName: suiteRegistry.User,
			Password: suiteRegistry.Password,
		},
		CreateNamespace: true,
		Name:            name,
		Wait:            wait,
		Timeout:         waitTimeout,
		RepoChart:       repoChart,
		Version:         chartVersion,
		Labels:          map[string]string{"DeployedBy": "TAPAISuite"},
	}
	for _, cv := range customValues {
		switch cv.Name {
		case helmParamPrefix + "namespace":
			namespace, ok := cv.Value.(string)
			if !ok {
				return fmt.Errorf("invalid type for namespace value: expected string, got %T", cv.Value)
			}
			req.Namespace = namespace
		case helmParamPrefix + "timeout":
			waitTimeoutFloat, ok := cv.Value.(float64) // JSON numbers are unmarshaled into float64
			if !ok {
				return fmt.Errorf("invalid type for timeout value: expected int, got %T", cv.Value)
			}
			waitTimeout := util.ToInt(waitTimeoutFloat)
			req.Timeout = time.Duration(waitTimeout) * time.Second
		default:
			expandDotKey(setValues, cv.Name, cv.Value)
		}
	}
	if req.Namespace == "" {
		return fmt.Errorf("namespace is required for installing AI Suite in cluster")
	}

	req.Values = setValues
	return c.apiserverGetter.InstallRelease(clusterCode, req)
}

func (c *Controller) upgradeAISuiteInCluster(clusterCode, namespace, name, chartVersion string, customValues []*aisuite.CustomValues) error {
	// 升级逻辑和安装类似，区别在于不接受部分参数，并且调用UpgradeRelease接口
	suiteRegistry, err := getSuiteRegistry(c.db)
	if err != nil {
		log.Errorf("failed to get suite registry: %v", err)
		return fmt.Errorf("failed to get suite registry: %w", err)
	}
	registryHost := strings.TrimPrefix(suiteRegistry.Address, "https://")
	registryHost = strings.TrimPrefix(registryHost, "http://")
	repoChart := fmt.Sprintf("oci://%s/%s/%s", registryHost, suiteChartProject, name)
	setValues := make(map[string]interface{})
	req := &helm.InstallOrUpgradeReleaseRequest{
		Wait:    wait,
		Timeout: waitTimeout,
	}
	for _, cv := range customValues {
		switch cv.Name {
		case helmParamPrefix + "timeout":
			waitTimeoutFloat, ok := cv.Value.(float64) // JSON numbers are unmarshaled into float64
			if !ok {
				return fmt.Errorf("invalid type for timeout value: expected int, got %T", cv.Value)
			}
			waitTimeout := util.ToInt(waitTimeoutFloat)
			req.Timeout = time.Duration(waitTimeout) * time.Second
		default:
			expandDotKey(setValues, cv.Name, cv.Value)
		}
	}
	req.Host = registryHost
	req.UserName = suiteRegistry.User
	req.Password = suiteRegistry.Password
	req.Namespace = namespace
	req.Name = name
	req.RepoChart = repoChart
	req.Version = chartVersion
	req.Labels = map[string]string{"DeployedBy": "TAPAISuite"}
	req.Values = setValues

	return c.apiserverGetter.UpgradeRelease(clusterCode, req)
}

// chartVersion可以为空，表示获取该套件的最新推送的版本
func getAISuiteInRegistry(ctx context.Context, suiteRegistry *db.Repository, name, chartVersion string) (*aisuite.GetAISuiteResp, error) {
	chart := &model.Artifact{}
	err := error(nil)

	if suiteRegistry == nil {
		return nil, fmt.Errorf("suite registry is nil")
	}
	if chartVersion != "" {
		registryOpts := harbor.DefaultOptions()
		registryCli, err := harbor.GetRegistryClient(suiteRegistry, registryOpts)
		if err != nil {
			log.Errorf("failed to get registry client: %v", err)
			return nil, fmt.Errorf("failed to get registry client: %w", err)
		}
		chart, err = registryCli.GetClient().GetArtifact(ctx, suiteChartProject, name, chartVersion)
		if err != nil {
			log.Errorf("failed to get artifact %s:%s from registry: %v", name, chartVersion, err)
			return nil, fmt.Errorf("failed to get artifact %s:%s from registry: %w", name, chartVersion, err)
		}
	} else {
		registryOpts := harbor.DefaultOptions().WithPage(1).WithPageSize(1).WithSort("-push_time").WithQuery("tags=~.")
		registryCli, err := harbor.GetRegistryClient(suiteRegistry, registryOpts)
		if err != nil {
			log.Errorf("failed to get registry client: %v", err)
			return nil, fmt.Errorf("failed to get registry client: %w", err)
		}
		charts, err := registryCli.GetClient().ListArtifacts(ctx, suiteChartProject, name)
		if err != nil {
			log.Errorf("failed to list artifacts in registry for suite %s: %v", name, err)
			return nil, fmt.Errorf("failed to list artifacts in registry for suite %s: %w", name, err)
		}
		if len(charts) == 0 {
			return nil, nil
		}
		chart = charts[0]
	}

	profile := chartToProfileAISuite(chart)
	customValueSchema, err := getCustomValueSchema(ctx, suiteRegistry, name, chart.Digest)
	if err != nil {
		log.Errorf("failed to get custom value schema for suite %s:%s: %v", name, profile.Version.ChartVersion, err)
		customValueSchema = nil // 获取schema失败不应该导致整个请求失败，所以这里不返回错误了
	}
	versionList, err := getAllVersionsOfAISuiteInRegistry(ctx, suiteRegistry, name)
	if err != nil {
		log.Errorf("failed to get all versions of AI Suite in registry for suite %s: %v", name, err)
		versionList = []*aisuite.AISuiteVersion{profile.Version} // 获取版本列表失败不应该导致整个请求失败，所以这里至少返回当前版本
	}
	return &aisuite.GetAISuiteResp{
		ProfileAISuite:    profile,
		InCluster:         false,
		VersionList:       versionList,
		CustomValueSchema: customValueSchema,
	}, nil
}

func chartToProfileAISuite(chart *model.Artifact) *aisuite.ProfileAISuite {
	simpleRepoName, _ := chart.ExtraAttrs["name"].(string)
	chartVersion, _ := chart.ExtraAttrs["version"].(string)
	appVersion, _ := chart.ExtraAttrs["appVersion"].(string)
	if appVersion == "" {
		appVersion = "devEdition"
	}
	displayVersion := getDisplayVersion(appVersion, chartVersion)
	description, ok := chart.ExtraAttrs["description"].(string)
	if !ok {
		description = fmt.Sprintf("AI套件: %s:%s", simpleRepoName, displayVersion)
	}

	return &aisuite.ProfileAISuite{
		Name:        simpleRepoName,
		Status:      deployStatusUndeployed,
		Description: description,
		Version: &aisuite.AISuiteVersion{
			AppVersion:     appVersion,
			ChartVersion:   chartVersion,
			DisplayVersion: displayVersion,
		},
	}
}

// 用oras拉取chart，解压后读取其中的tap_aisuite_values.json, 作为套件的定制化参数schema
func getCustomValueSchema(ctx context.Context, suiteRegistry *db.Repository, name, digest string) (json.RawMessage, error) {
	if suiteRegistry == nil {
		return nil, fmt.Errorf("suite registry is nil")
	}
	if name == "" {
		return nil, fmt.Errorf("suite name is empty")
	}
	if digest == "" {
		return nil, fmt.Errorf("digest is empty")
	}

	orasClient, err := oras.NewClient(suiteRegistry, oras.Insecure())
	if err != nil {
		log.Errorf("failed to create oras client: %v", err)
		return nil, fmt.Errorf("failed to create oras client: %w", err)
	}

	artifactRef := fmt.Sprintf("%s/%s@%s", suiteChartProject, name, digest)
	schemaBytes, err := orasClient.PullFile(ctx, artifactRef, jsonSchemaFileName, maxSchemaSize)
	if err != nil {
		log.Errorf("failed to pull custom value schema from artifact %s: %v", artifactRef, err)
		return nil, fmt.Errorf("failed to pull custom value schema from artifact %s: %w", artifactRef, err)
	}
	if json.Valid(schemaBytes) {
		return json.RawMessage(schemaBytes), nil
	} else {
		log.Errorf("custom value schema pulled from artifact %s is not valid JSON", artifactRef)
		return nil, fmt.Errorf("custom value schema pulled from artifact %s is not valid JSON", artifactRef)
	}
}

func getDisplayVersion(appVersion, chartVersion string) string {
	return appVersion + "@" + chartVersion
}

func getAllVersionsOfAISuiteInRegistry(ctx context.Context, suiteRegistry *db.Repository, name string) ([]*aisuite.AISuiteVersion, error) {
	registryOpts := harbor.DefaultOptions().WithPage(1).WithPageSize(100).WithQuery("tags=~.,Type=" + chartArtifactType).WithSort("-push_time")
	registryCli, err := harbor.GetRegistryClient(suiteRegistry, registryOpts)
	if err != nil {
		log.Errorf("failed to get registry client: %v", err)
		return nil, err
	}
	charts, err := registryCli.GetClient().ListArtifacts(ctx, suiteChartProject, name)
	if err != nil {
		log.Errorf("failed to list artifacts in registry for suite %s: %v", name, err)
		return nil, err
	}
	versionList := make([]*aisuite.AISuiteVersion, 0, len(charts))
	for _, chart := range charts {
		appVersion, _ := chart.ExtraAttrs["appVersion"].(string)
		chartVersion, _ := chart.ExtraAttrs["version"].(string)
		displayVersion := getDisplayVersion(appVersion, chartVersion)
		versionList = append(versionList, &aisuite.AISuiteVersion{
			AppVersion:     appVersion,
			ChartVersion:   chartVersion,
			DisplayVersion: displayVersion,
		})
	}
	return versionList, nil
}

func (c *Controller) getAISuiteInCluster(clusterCode, name, chartVersion, namespace string) (*aisuite.GetAISuiteResp, error) {
	releaseInCluster, err := c.apiserverGetter.GetHelmReleaseByName(clusterCode, namespace, name)
	if err != nil {
		log.Errorf("failed to get helm release [%s:%s] in cluster %s: %v", namespace, name, clusterCode, err)
		return nil, fmt.Errorf("failed to get helm release in cluster: %w", err)
	}
	if releaseInCluster.Labels["DeployedBy"] != "TAPAISuite" {
		return nil, fmt.Errorf("helm release %s in namespace %s is not deployed by TAPAISuite", name, namespace)
	}
	profile := releaseElementToProfileAISuite(releaseInCluster)
	if chartVersion != "" && profile.Version.ChartVersion != chartVersion {
		return nil, fmt.Errorf("chart version mismatch for release %s in namespace %s: expected %s, got %s", name, namespace, chartVersion, profile.Version.ChartVersion)
	}
	versionList := make([]*aisuite.AISuiteVersion, 0)
	versionList = append(versionList, profile.Version)
	return &aisuite.GetAISuiteResp{
		ProfileAISuite: profile,
		InCluster:      true,
		MaxRevision:    releaseInCluster.Revision, // 目前还不做回滚功能，所以MaxRevision就是当前版本的Revision
		VersionList:    versionList,
	}, nil
}

func listAISuitesInRegistry(ctx *gin.Context, suiteRegistry *db.Repository) ([]*aisuite.ProfileAISuite, error) {
	if suiteRegistry == nil {
		return nil, fmt.Errorf("suite registry is nil")
	}

	registryOpts := harbor.DefaultOptions().WithPageSize(100).WithPage(1)
	registryCli, err := harbor.GetRegistryClient(suiteRegistry, registryOpts)
	if err != nil {
		log.Errorf("failed to get registry client: %v", err)
		return nil, err
	}

	reposInSuiteRegistry := make([]*model.Repository, 0)
	for {
		repos, err := registryCli.GetClient().ListRepositories(ctx, suiteChartProject)
		if err != nil {
			log.Errorf("failed to list repositories in suite registry: %v", err)
			return nil, err
		}
		reposInSuiteRegistry = append(reposInSuiteRegistry, repos...)
		if int64(len(repos)) < registryOpts.PageSize {
			break
		}
		registryOpts = registryOpts.WithPage(registryOpts.Page + 1)
		if registryOpts.Page > 20 {
			log.Errorf("too many repositories in suite registry, page: %d, pageSize: %d", registryOpts.Page, registryOpts.PageSize)
			break
		}
	}

	aiSuites, err := filterAISuitesFromRepos(ctx, suiteRegistry, reposInSuiteRegistry)
	if err != nil {
		log.Errorf("failed to get AI Suites from repos: %v", err)
		return nil, err
	}

	return aiSuites, nil

}

// 保留至少有一个Chart类型的Artifact的Repo，其他的Repo都丢弃
func filterAISuitesFromRepos(ctx context.Context, suiteRegistry *db.Repository, repos []*model.Repository) ([]*aisuite.ProfileAISuite, error) {
	optiongsWithQuery := harbor.DefaultOptions().WithPageSize(1).WithPage(1).WithQuery("tags=~.,Type=" + chartArtifactType).WithSort("-push_time")
	registryCli, err := harbor.GetRegistryClient(suiteRegistry, optiongsWithQuery)
	if err != nil {
		log.Errorf("failed to get registry client: %v", err)
		return nil, err
	}
	aiSuites := make([]*aisuite.ProfileAISuite, 0)
	for _, repo := range repos {
		simpleRepoName := harbor.GetSimpleRepoName(repo.Name)
		charts, err := registryCli.GetClient().ListArtifacts(ctx, suiteChartProject, simpleRepoName)
		if err != nil {
			log.Warnf("failed to list artifacts in repo %s, error: %v", simpleRepoName, err)
			continue
		}
		if len(charts) == 0 {
			continue
		}
		chart := charts[0]
		description, ok := chart.ExtraAttrs["description"].(string)
		if !ok {
			description = "AI套件 —— " + simpleRepoName
		}
		appVersion, _ := chart.ExtraAttrs["appVersion"].(string)
		chartVersion, _ := chart.ExtraAttrs["version"].(string)
		aiSuites = append(aiSuites, &aisuite.ProfileAISuite{
			Name:        simpleRepoName,
			Description: description,
			Status:      deployStatusUndeployed,
			Version: &aisuite.AISuiteVersion{
				AppVersion:     appVersion,
				ChartVersion:   chartVersion,
				DisplayVersion: appVersion + "@" + chartVersion,
			},
		})
	}
	return aiSuites, nil
}

func (c *Controller) listAISuitesInCluster(clusterCode string) ([]*aisuite.ProfileAISuite, error) {
	releases, err := c.apiserverGetter.ListHelmReleases(clusterCode, "", aisuiteReleaseLabel)
	if err != nil {
		log.Errorf("failed to list helm releases in cluster: %v", err)
		return nil, fmt.Errorf("failed to list helm releases in cluster: %w", err)
	}
	aiSuites := make([]*aisuite.ProfileAISuite, 0, len(releases))
	for _, release := range releases {
		aiSuites = append(aiSuites, releaseElementToProfileAISuite(release))
	}
	return aiSuites, nil
}

func releaseElementToProfileAISuite(release *helm.ReleaseElement) *aisuite.ProfileAISuite {
	return &aisuite.ProfileAISuite{
		Name:        release.Name,
		Description: release.Description,
		Status:      release.Status.String(),
		Version: &aisuite.AISuiteVersion{
			AppVersion:     release.AppVersion,
			ChartVersion:   release.ChartVersion,
			Revision:       release.Revision,
			DisplayVersion: release.AppVersion + "@" + release.ChartVersion,
		},
		Namespace: release.Namespace,
	}
}

// 入参底层数组可能会被修改
func disruptiveMergeAiSuites(suitesInRegistry []*aisuite.ProfileAISuite, suitesInCluster []*aisuite.ProfileAISuite) []*aisuite.ProfileAISuite {
	clusterMap := make(map[string]*aisuite.ProfileAISuite, len(suitesInCluster))
	for _, suite := range suitesInCluster {
		clusterMap[suite.Name] = suite
	}

	result := make([]*aisuite.ProfileAISuite, 0, len(suitesInRegistry)+len(suitesInCluster))
	seen := make(map[string]bool, len(suitesInRegistry))
	for _, suite := range suitesInRegistry {
		if suiteInCluster, ok := clusterMap[suite.Name]; ok {
			result = append(result, suiteInCluster)
		} else {
			result = append(result, suite)
		}
		seen[suite.Name] = true
	}
	for _, suite := range suitesInCluster {
		if !seen[suite.Name] {
			result = append(result, suite)
		}
	}
	return result
}

// expandDotKey inserts a value into a nested map by expanding dot-separated keys.
// E.g. expandDotKey(m, "global.image.tag", "v1.0.0") sets m["global"]["image"]["tag"] = "v1.0.0".
// This matches the behavior of `helm install --set global.image.tag=v1.0.0`.
func expandDotKey(m map[string]interface{}, key string, value interface{}) {
	dotIdx := strings.Index(key, ".")
	if dotIdx == -1 {
		m[key] = value
		return
	}
	prefix := key[:dotIdx]
	rest := key[dotIdx+1:]
	sub, ok := m[prefix].(map[string]interface{})
	if !ok {
		sub = make(map[string]interface{})
		m[prefix] = sub
	}
	expandDotKey(sub, rest, value)
}

func getSuiteRegistry(dbInstance *gorm.DB) (*db.Repository, error) {
	registryModel := &db.Repository{}
	suiteRegistry, err := registryModel.GetOrderBy(dbInstance, "created_at", false)
	if err != nil {
		log.Errorf("get suite registry failed: %v", err)
		return nil, err
	}

	// 数据合法性检查：防止数据库脏数据或空结果
	if suiteRegistry.Id == 0 {
		log.Error("suite registry not found or invalid: Id is zero")
		return nil, fmt.Errorf("suite registry not found")
	}
	if suiteRegistry.Name == "" {
		log.Error("suite registry has invalid data: Name is empty")
		return nil, fmt.Errorf("suite registry data is incomplete")
	}
	if suiteRegistry.Address == "" {
		log.Errorf("suite registry[%s] has invalid data: Address is empty", suiteRegistry.Name)
		return nil, fmt.Errorf("suite registry data is incomplete")
	}
	return suiteRegistry, nil
}

