package aisuite

import (
	"net/http"

	"github.com/gin-gonic/gin"
	"gorm.io/gorm"

	"code.srdcloud.cn/TDP-PaaS/TDP-CODE/paas-controller/pkg/backend/aisuite/controller"
	"code.srdcloud.cn/TDP-PaaS/TDP-CODE/paas-controller/pkg/backend/cluster/manager"
	"code.srdcloud.cn/TDP-PaaS/TDP-CODE/paas-controller/pkg/models"
	"code.srdcloud.cn/TDP-PaaS/TDP-CODE/paas-controller/pkg/models/aisuite"

	"code.srdcloud.cn/TDP-PaaS/TDP-CODE/paas-controller/pkg/log"
)

type Server struct {
	controller *controller.Controller
}

func newServer(db *gorm.DB, apiserverGetter manager.ApiserverGetter) (*Server, error) {
	newController, err := controller.NewController(db, apiserverGetter)
	if err != nil {
		return nil, err
	}
	return &Server{controller: newController}, nil
}

func (s *Server) ListAISuites(ctx *gin.Context) {
	req := &aisuite.ListAISuitesReq{}
	if err := ctx.ShouldBindQuery(req); err != nil {
		log.Errorf("invalid query parameters: %v", err)
		ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusBadRequest, err))
		return
	}

	aiSuites, err := s.controller.ListAISuites(ctx, req.ClusterCode)
	if err != nil {
		log.Errorf("failed to list AI Suites: %v", err)
		ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusInternalServerError, err))
		return
	}

	ctx.JSON(http.StatusOK, models.WrapSuccessResp(aiSuites))
}

func (s *Server) GetAISuite(ctx *gin.Context) {
	req := &aisuite.GetAISuiteReq{}
	if err := ctx.ShouldBindQuery(req); err != nil {
		log.Errorf("invalid query parameters: %v", err)
		ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusBadRequest, err))
		return
	}
	if err := ctx.ShouldBindUri(req); err != nil {
		log.Errorf("invalid URI parameters: %v", err)
		ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusBadRequest, err))
		return
	}

	aiSuite, err := s.controller.GetAISuite(ctx, req.ClusterCode, req.Name, req.ChartVersion, req.Namespace)
	if err != nil {
		log.Errorf("failed to get AI Suite: %v", err)
		ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusInternalServerError, err))
		return
	}

	ctx.JSON(http.StatusOK, models.WrapSuccessResp(aiSuite))
}

func (s *Server) GetAISuiteReadme(ctx *gin.Context) {
	req := &aisuite.GetAISuiteReadmeReq{}
	if err := ctx.ShouldBindQuery(req); err != nil {
		log.Errorf("invalid query parameters: %v", err)
		ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusBadRequest, err))
		return
	}
	if err := ctx.ShouldBindUri(req); err != nil {
		log.Errorf("invalid URI parameters: %v", err)
		ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusBadRequest, err))
		return
	}

	readme, err := s.controller.GetAISuiteReadme(ctx, req.Name, req.ChartVersion)
	if err != nil {
		log.Errorf("failed to get AI Suite README: %v", err)
		ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusInternalServerError, err))
		return
	}

	ctx.JSON(http.StatusOK, models.WrapSuccessResp(readme))
}

func (s *Server) OperateAISuiteInCluster(ctx *gin.Context) {
	var req aisuite.OperateAISuiteReq
	if err := ctx.ShouldBindJSON(&req); err != nil {
		log.Errorf("invalid request body: %v", err)
		ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusBadRequest, err))
		return
	}
	if err := ctx.ShouldBindUri(&req); err != nil {
		log.Errorf("invalid URI parameters: %v", err)
		ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusBadRequest, err))
		return
	}

	suiteResp, err := s.controller.OperateAISuiteInCluster(ctx, &req)
	if err != nil {
		log.Errorf("failed to operate AI Suite in cluster: %v", err)
		ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusInternalServerError, err))
		return
	}
	ctx.JSON(http.StatusOK, models.WrapSuccessResp(suiteResp))
}
